  const handles = document.querySelectorAll('.col-resize-handle');
  const handleParents = [];
  handles.forEach(h => {
    const parent = h.parentElement;
    const style = window.getComputedStyle(h);
    handleParents.push({
      parentTag: parent.tagName,
      parentText: parent.textContent.trim().substring(0, 30),
      cursor: style.cursor,
      position: style.position,
      width: style.width,
      parentPosition: window.getComputedStyle(parent).position
    });
  });

  // Find table headers another way
  const allTh = document.querySelectorAll('th');
  const thInfo = [];
  allTh.forEach(th => {
    thInfo.push({
      text: th.textContent.trim().substring(0, 20),
      hasHandle: !!th.querySelector('.col-resize-handle'),
      width: th.style.width || 'auto'
    });
  });

  return { handles: handleParents, allTh: thInfo };
}

