() => {
  // Find the Headline th and its resize handle
  const ths = document.querySelectorAll('th');
  let headlineTh = null;
  let handle = null;
  for (const th of ths) {
    if (th.textContent.trim() === 'Headline') {
      headlineTh = th;
      handle = th.querySelector('.col-resize-handle');
      break;
    }
  }
  if (!headlineTh || !handle) return { error: 'Headline th or handle not found' };

  const beforeWidth = headlineTh.getBoundingClientRect().width;

  // Get handle position
  const rect = handle.getBoundingClientRect();
  const startX = rect.left + rect.width / 2;
  const startY = rect.top + rect.height / 2;

  // Simulate mousedown on handle
  handle.dispatchEvent(new MouseEvent('mousedown', {
    clientX: startX, clientY: startY, bubbles: true, cancelable: true
  }));

  // Simulate mousemove (drag 150px to the right)
  document.dispatchEvent(new MouseEvent('mousemove', {
    clientX: startX + 150, clientY: startY, bubbles: true, cancelable: true
  }));

  const duringWidth = headlineTh.getBoundingClientRect().width;

  // Simulate mouseup
  document.dispatchEvent(new MouseEvent('mouseup', {
    clientX: startX + 150, clientY: startY, bubbles: true, cancelable: true
  }));

  const afterWidth = headlineTh.getBoundingClientRect().width;
  const styleWidth = headlineTh.style.width;

  // Check localStorage
  const stored = localStorage.getItem('instnews_column_widths');

  // Check table layout
  const table = headlineTh.closest('table');
  const tableLayout = window.getComputedStyle(table).tableLayout;

  return {
    beforeWidth: Math.round(beforeWidth),
    duringWidth: Math.round(duringWidth),
    afterWidth: Math.round(afterWidth),
    styleWidth,
    localStorage: stored,
    tableLayout
  };
}

