() => {
  // Hide all gate/modal overlays
  const gates = document.querySelectorAll('.auth-gate, .tier-gate, .sign-in-overlay, .upgrade-overlay');
  gates.forEach(g => g.style.display = 'none');

  // Also try by ID patterns
  const ids = ['sign-in-gate', 'tier-gate', 'auth-overlay', 'upgrade-gate'];
  ids.forEach(id => {
    const el = document.getElementById(id);
    if (el) el.style.display = 'none';
  });

  // Brute force: hide any overlay that's covering the terminal
  document.querySelectorAll('[class*="gate"], [class*="overlay"]').forEach(el => {
    const style = window.getComputedStyle(el);
    if (style.position === 'fixed' || style.position === 'absolute') {
      if (style.zIndex > 1) {
        el.style.display = 'none';
      }
    }
  });

  return { done: true, hiddenCount: gates.length };
}

