() => {
  // Find column settings panel
  const panel = document.querySelector('.column-settings');
  if (!panel) return { error: 'Column settings panel not found' };

  const items = panel.querySelectorAll('.col-setting-item, [class*="col-setting"]');
  const panelInfo = [];

  items.forEach(item => {
    const label = item.textContent.trim();
    const toggle = item.querySelector('input[type="checkbox"]');
    panelInfo.push({
      label: label.substring(0, 30),
      checked: toggle ? toggle.checked : null,
      disabled: toggle ? toggle.disabled : null
    });
  });

  // Find and click Sentiment toggle to turn it off
  let sentimentToggle = null;
  items.forEach(item => {
    if (item.textContent.includes('Sentiment')) {
      sentimentToggle = item.querySelector('input[type="checkbox"]');
    }
  });

  if (sentimentToggle && !sentimentToggle.disabled) {
    sentimentToggle.click();
  }

  // Get visible columns after toggle
  const ths = document.querySelectorAll('th');
  const visibleCols = [];
  ths.forEach(th => visibleCols.push(th.textContent.trim()));

  return {
    panelItems: panelInfo,
    sentimentToggled: !!sentimentToggle,
    visibleColumnsAfterToggle: visibleCols
  };
}

