  if (!sentimentItem) return { error: 'Sentiment item not found' };

  const toggle = sentimentItem.querySelector('input[type="checkbox"], .toggle-switch input, input');
  if (!toggle) {
    // Try clicking the toggle switch directly
    const switchEl = sentimentItem.querySelector('.toggle-switch, .switch, label');
    if (switchEl) switchEl.click();
    else sentimentItem.click();
  } else {
    toggle.click();
  }

  // Wait a tick for re-render, check visible columns
  const ths = document.querySelectorAll('th');
  const visibleCols = [];
  ths.forEach(th => visibleCols.push(th.textContent.trim()));

  return {
    sentimentFound: true,
    visibleColumnsAfterToggle: visibleCols,
    sentimentHidden: !visibleCols.includes('Sentiment')
  };
}

