() => {
  // Check current state - widths should be preserved
  const ths = document.querySelectorAll('th');
  const before = [];
  ths.forEach(th => {
    before.push({
      text: th.textContent.trim(),
      styleWidth: th.style.width || 'none',
      actualWidth: Math.round(th.getBoundingClientRect().width),
      hasHandle: !!th.querySelector('.col-resize-handle')
    });
  });

  // Now resize Source column by dragging 50px right
  let sourceTh = null;
  let handle = null;
  for (const th of ths) {
    if (th.textContent.trim() === 'Source') {
      sourceTh = th;
      handle = th.querySelector('.col-resize-handle');
      break;
    }
  }

  if (!handle) return { error: 'Source handle not found', before };

  const rect = handle.getBoundingClientRect();
  const startX = rect.left + rect.width / 2;
  const startY = rect.top + rect.height / 2;

  handle.dispatchEvent(new MouseEvent('mousedown', {
    clientX: startX, clientY: startY, bubbles: true, cancelable: true
  }));
  document.dispatchEvent(new MouseEvent('mousemove', {
    clientX: startX + 50, clientY: startY, bubbles: true, cancelable: true
  }));
  document.dispatchEvent(new MouseEvent('mouseup', {
    clientX: startX + 50, clientY: startY, bubbles: true, cancelable: true
  }));

  const stored = JSON.parse(localStorage.getItem('instnews_column_widths') || '{}');

  return {
    before,
    localStorage: stored,
    sourceResizedTo: stored.source,
    resizeWorkedAfterToggle: stored.source === 157 // 107 + 50
  };
}

